<?php require_once __DIR__.'/../config.php'; require_once __DIR__.'/../includes/Database.php'; require_once __DIR__.'/../includes/RedisClient.php'; require_once __DIR__.'/../includes/Session.php'; require_once __DIR__.'/../includes/Auth.php'; require_once __DIR__.'/../includes/Monitor.php'; Session::start();Auth::require(); $db=Database::getInstance();$summary=Monitor::getSummary();$sites=$db->fetchAll("SELECT * FROM `sites` ORDER BY display_order ASC, name ASC");$cs=Monitor::getCurrentStatus();$ri=$db->fetchAll("SELECT i.*,s.name as site_name FROM `incidents` i LEFT JOIN `sites` s ON i.site_id=s.id ORDER BY i.started_at DESC LIMIT 5");$rc=$db->fetchAll("SELECT c.*,s.name as site_name FROM `checks` c LEFT JOIN `sites` s ON c.site_id=s.id ORDER BY c.checked_at DESC LIMIT 10");$u=Auth::user();$lb=['ok'=>'在线','error'=>'离线','warning'=>'警告','timeout'=>'超时','unknown'=>'未知'];$sl=['investigating'=>'调查中','identified'=>'已定位','monitoring'=>'监控中','resolved'=>'已解决'];?><!DOCTYPE html><html lang="zh-CN"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1.0"><title>仪表盘 - <?php echo APP_NAME;?></title><link href="https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700&display=swap" rel="stylesheet"><link href="https://fonts.googleapis.com/icon?family=Material+Icons" rel="stylesheet"><link href="/assets/css/admin.css" rel="stylesheet"></head><body><div class="admin-layout"><?php include __DIR__.'/sidebar.php';?><main class="main-content"><div class="top-bar"><h2>仪表盘</h2><div class="top-bar-right"><span class="user-info"><span class="material-icons">person</span><?php echo e($u['username']);?></span></div></div><div class="stats-grid"><div class="stat-card"><div class="stat-icon" style="background:rgba(67,97,238,.1)"><span class="material-icons">dns</span></div><div class="stat-info"><span class="stat-number"><?php echo $summary['total_sites'];?></span><span class="stat-label">监控站点</span></div></div><div class="stat-card"><div class="stat-icon" style="background:rgba(46,204,113,.1);color:#2ecc71"><span class="material-icons">check_circle</span></div><div class="stat-info"><span class="stat-number"><?php echo $summary['online_sites'];?></span><span class="stat-label">在线</span></div></div><div class="stat-card"><div class="stat-icon" style="background:rgba(231,76,60,.1);color:#e74c3c"><span class="material-icons">error</span></div><div class="stat-info"><span class="stat-number"><?php echo $summary['offline_sites'];?></span><span class="stat-label">离线</span></div></div><div class="stat-card"><div class="stat-icon" style="background:rgba(248,150,30,.1);color:#f8961e"><span class="material-icons">speed</span></div><div class="stat-info"><span class="stat-number"><?php echo $summary['avg_response'];?> ms</span><span class="stat-label">平均响应</span></div></div></div><div class="dashboard-grid"><div class="card"><div class="card-header"><h3>站点状态</h3><a href="/admin/sites.php" class="btn-sm">管理站点</a></div><div class="card-body"><?php if(empty($sites)):?><p class="text-muted">暂无监控站点</p><?php else:?><table class="table"><thead><tr><th>站点</th><th>状态</th><th>响应</th><th>最后检测</th></tr></thead><tbody><?php foreach($sites as $s):$st=$cs[$s['id']]??null;$sc=$st['status']??'unknown';?><tr><td><a href="/admin/sites.php?edit=<?php echo $s['id'];?>"><?php echo e($s['name']);?></a></td><td><span class="badge badge-<?php echo $sc;?>"><?php echo $lb[$sc]??'未知';?></span></td><td><?php echo (int)($st['response_time']??0);?> ms</td><td><?php echo $st['checked_at']?e($st['checked_at']):'N/A';?></td></tr><?php endforeach;?></tbody></table><?php endif;?></div></div><div class="card"><div class="card-header"><h3>最近事件</h3><a href="/admin/incidents.php" class="btn-sm">全部</a></div><div class="card-body"><?php if(empty($ri)):?><p class="text-muted">暂无事件</p><?php else:?><table class="table"><thead><tr><th>站点</th><th>标题</th><th>状态</th></tr></thead><tbody><?php foreach($ri as $i):?><tr><td><?php echo e($i['site_name']??'N/A');?></td><td><?php echo e($i['title']);?></td><td><span class="badge badge-<?php echo $i['status'];?>"><?php echo $sl[$i['status']]??$i['status'];?></span></td></tr><?php endforeach;?></tbody></table><?php endif;?></div></div></div><div class="card"><div class="card-header"><h3>最近检测记录</h3></div><div class="card-body"><table class="table"><thead><tr><th>站点</th><th>状态</th><th>HTTP</th><th>响应</th><th>时间</th></tr></thead><tbody><?php foreach($rc as $c):?><tr><td><?php echo e($c['site_name']??'N/A');?></td><td><span class="badge badge-<?php echo $c['status'];?>"><?php echo $lb[$c['status']]??$c['status'];?></span></td><td><?php echo $c['http_code']??'N/A';?></td><td><?php echo (int)($c['response_time']??0);?> ms</td><td><?php echo e($c['checked_at']);?></td></tr><?php endforeach;?></tbody></table></div></div></main></div></body></html>